const TENANT_LOCAL_RELEASE_BUILD_PROP_KEY = 'TENANT_LOCAL_RELEASE_BUILD';
const TENANT_LOCAL_RELEASE_SYNCED_AT_PROP_KEY = 'TENANT_LOCAL_RELEASE_SYNCED_AT';
