    lock.releaseLock();
  }

  const returnedAt = nowIso_();
  if (meta.skipDraftPersist === true) {
    draftSaveMs = 0;
  } else {
    const draftSaveStartedAt = Date.now();
    upsertTeacherCommentDrafts_(returnedDrafts.map(item => ({
