const MASTER_GAS_API_LOCK_TIMEOUT_MS = 0;
const MASTER_GAS_API_MAX_LIMIT = 500;
const MASTER_GAS_API_DEFAULT_LIMIT = 100;
const MASTER_GAS_API_ALLOWED_ACTIONS = Object.freeze({
  PING: true,
  APPEND_RECORD: true,
  GET_RECORDS: true,
  UPSERT_CONFIG: true,
  GET_CONFIG: true,
  UPSERT_MASTER: true,
